export async function loadSkillFromDir(dirPath: string, source: SkillSource): Promise<Skill> {
  const skillPath = path.join(dirPath, 'SKILL.md')
  let content: string
  try {
    content = fs.readFileSync(skillPath, 'utf-8')
  }

findings.suggestion:
BEFORE:
export async function loadSkillFromDir(dirPath: string, source: SkillSource): Promise<Skill> {
  ...
  content = fs.readFileSync(skillPath, 'utf-8')
  ...
}

AFTER (option A - make truly async):
export async function loadSkillFromDir(dirPath: string, source: SkillSource): Promise<Skill> {
  ...
  content = await fs.promises.readFile(skillPath, 'utf-8')
  ...
}

AFTER (option B - make synchronous):
export function loadSkillFromDir(dirPath: string, source: SkillSource): Skill {
  ...
  content = fs.readFileSync(skillPath, 'utf-8')
  ...
}

WHY: Either commit to async I/O (fs.promises) or drop the async keyword. Mixing async function signatures with synchronous bodies adds cognitive overhead and misleads about blocking behavior.

