findings.suggestion:
BEFORE:
  activate(id: string): boolean {
    const entry = this.entries.get(id)
    if (!entry) { return false }
    entry.active = true
    return true
  }
  deactivate(id: string): boolean {
    const entry = this.entries.get(id)
    if (!entry) { return false }
    entry.active = false
    return true
  }

AFTER:
  activate(id: string): boolean {
    return this.setActive(id, true)
  }
  deactivate(id: string): boolean {
    return this.setActive(id, false)
  }
  private setActive(id: string, active: boolean): boolean {
    const entry = this.entries.get(id)
    if (!entry) { return false }
    entry.active = active
    return true
  }

WHY: Extracts the shared pattern into a private method while keeping the public API clear and descriptive. The duplication is mild enough that this is optional -- the current code is also fine.

